mapper.update:
UPDATE esg.tb_ohs_corractive_action_request
SET write_dt=#{writeDt},
req_dt=#{reqDt},
nonconformities=#{nonconformities},
measures=#{measures},
validate=#{validate},
required=#{required},
final_check_dt=#{finalCheckDt},
use_yn=#{useYn},
updated_at=now(),
updated_by=#{updatedBy}
WHERE  write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
  AND doc_seq = #{docSeq}
  AND doc_detail_seq = #{docDetailSeq}

UPDATE esg.tb_ohs_corractive_action_request
SET use_yn = 'N',
updated_at=now(),
updated_by=#{updatedBy}
WHERE  write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
  AND doc_seq = #{docSeq}
  AND doc_detail_seq = #{docDetailSeq}

mapper.select:
select car.*,tarr.orgn_id,toi.orgn_nm,axp.audit_nm from esg.tb_ohs_corractive_action_request car
left join esg.tb_audit_result_report tarr on tarr.write_year = #{writeYear}
  AND tarr.doc_no = #{docNo}
  AND tarr.doc_seq = #{docSeq}
LEFT JOIN esg.tb_orgn_info toi on toi.orgn_id = tarr.orgn_id
LEFT JOIN esg.tb_audit_execution_plan axp on  axp.write_year=#{writeYear}
  AND axp.doc_no = #{docNo}
WHERE car.write_year = #{writeYear}
  AND car.doc_no = #{docNo}
  AND car.doc_type = #{docType}
  AND car.doc_seq = #{docSeq}
  AND car.doc_detail_seq = #{docDetailSeq}
